// Generated by OrchestKit Claude Plugin
// Created: 2026-07-01

// Generate a lightweight docs search index from MDX frontmatter.
//
// WHY: docs/site/app/api/ask (NLWeb) + /api/mcp searchDocs() only need
// {url, title, description} per page — but the previous implementation loaded
// the entire compiled Fumadocs source (@/.source/server) at module init, which
// cold-started the /ask serverless function at ~3.5-3.9s. Agent-readiness
// scanners (orank) probe /ask cold and time out (>~2.5-3.5s) => the NLWeb
// checks failed even though the endpoint is fully conformant when warm.
//
// This index is a small, dependency-free .ts data module. Loading it cold is
// sub-second, so searchDocs() no longer needs the heavy source at all.
// Regenerated by scripts/build-plugins.sh alongside generate-docs-data.js.
//
// URL derivation mirrors Fumadocs' default file-router (baseUrl "/docs"):
//   content/docs/foo/bar.mdx   -> /docs/foo/bar
//   content/docs/foo/index.mdx -> /docs/foo
//   (route-group) folders are stripped; a frontmatter `slug` overrides.

const fs = require("node:fs");
const path = require("node:path");
const { parseYamlFrontmatter } = require("./lib/parse-frontmatter");

const ROOT = path.resolve(__dirname, "..");
const CONTENT_DIR = path.join(ROOT, "docs/site/content/docs");
const OUT_FILE = path.join(ROOT, "docs/site/lib/generated/docs-search-index.ts");

function walk(dir) {
	const out = [];
	for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
		const full = path.join(dir, entry.name);
		if (entry.isDirectory()) out.push(...walk(full));
		else if (entry.name.endsWith(".mdx")) out.push(full);
	}
	return out;
}

function toUrl(relPath, slug) {
	if (slug) return `/docs/${String(slug).replace(/^\/+/, "")}`;
	let p = relPath.replace(/\\/g, "/").replace(/\.mdx$/, "");
	p = p.replace(/\/index$/, "").replace(/^index$/, "");
	// strip Fumadocs route-group segments like "(marketing)"
	p = p
		.split("/")
		.filter((seg) => seg && !/^\(.*\)$/.test(seg))
		.join("/");
	return p ? `/docs/${p}` : "/docs";
}

function main() {
	if (!fs.existsSync(CONTENT_DIR)) {
		console.error(`gen-docs-search-index: content dir missing: ${CONTENT_DIR}`);
		process.exit(1);
	}
	const files = walk(CONTENT_DIR).sort();
	const entries = [];
	for (const file of files) {
		const rel = path.relative(CONTENT_DIR, file);
		const raw = fs.readFileSync(file, "utf8");
		const { frontmatter: fm } = parseYamlFrontmatter(raw);
		const title = (fm.title || "").trim();
		if (!title) continue; // skip pages without a title (meta-only / drafts)
		entries.push({
			url: toUrl(rel, fm.slug),
			title,
			description: (fm.description || "").trim(),
		});
	}
	// de-dupe by url (index.mdx + dir collisions), keep first
	const seen = new Set();
	const unique = entries.filter((e) => (seen.has(e.url) ? false : seen.add(e.url)));

	const body = `// AUTO-GENERATED by scripts/gen-docs-search-index.js — do not edit.
// Lightweight {url,title,description} index so searchDocs() (NLWeb /ask + MCP)
// need not load the heavy Fumadocs source at cold start. Regenerated on build.

export type DocSearchEntry = { url: string; title: string; description: string };

export const DOCS_SEARCH_INDEX: DocSearchEntry[] = ${JSON.stringify(unique, null, 2)};
`;
	fs.mkdirSync(path.dirname(OUT_FILE), { recursive: true });
	fs.writeFileSync(OUT_FILE, body);
	console.log(`gen-docs-search-index: wrote ${unique.length} entries -> ${path.relative(ROOT, OUT_FILE)}`);
}

main();
